translations = {'I go into the remember password page': 'Entro en la página de recordar contraseña.', 'I see the remember password page': 'Veo la página para recordar contraseña.', 'I fill the email and click on remember password': 'Completo el correo electrónico y hago clic en recordar contraseña.', 'I see the confirmation recovery page': 'Veo la página de recuperación de confirmación.', 'I click on back from remember password': 'Hago clic en Atrás desde recordar contraseña.', 'I see the Login page': 'Veo la página de inicio de sesión', 'I click on resend email recovery password': 'Hago clic en reenviar contraseña de recuperación de correo electrónico', 'I click on back from confirm recovery pass': 'Hago clic en Atrás para confirmar el pase de recuperación.'}
